<?php
namespace App\Http\Controllers\CommandCenter\Customers; use App\Http\Controllers\Controller; use App\Http\Requests\Customers\CustomerGroupRequest; use App\Repositories\Customers\CustomerGroupRepository; use App\Repositories\Customers\CustomerRepository; use App\Services\Customers\CustomerGroupService; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\View\View;
class CustomerGroupController extends Controller { public function index(Request $r,CustomerGroupRepository $repo):View{return view('command-center.customers.groups.index',['groups'=>$repo->paginateForCompany($r->user()->company_id)]);} public function store(CustomerGroupRequest $r,CustomerGroupService $service):RedirectResponse{$service->create($r->user(),$r->validated());return back()->with('status','Customer group created.');} public function update(CustomerGroupRequest $r,CustomerGroupRepository $repo,CustomerGroupService $service):RedirectResponse{$service->update($repo->findForCompany($r->user()->company_id,(int)$r->route('group')),$r->validated());return back()->with('status','Customer group updated.');} public function destroy(Request $r,CustomerGroupRepository $repo,CustomerGroupService $service):RedirectResponse{$service->delete($repo->findForCompany($r->user()->company_id,(int)$r->route('group')));return back()->with('status','Customer group moved to trash.');} public function restore(Request $r,CustomerGroupRepository $repo,CustomerGroupService $service):RedirectResponse{$service->restore($repo->findForCompany($r->user()->company_id,(int)$r->route('group'),true));return back();} public function assign(Request $r,CustomerRepository $customers,CustomerGroupRepository $groups,CustomerGroupService $service):RedirectResponse{$r->validate(['customer_group_id'=>['required','integer']]);$service->assign($customers->findForCompany($r->user()->company_id,(int)$r->route('customer')),$groups->findForCompany($r->user()->company_id,(int)$r->customer_group_id),$r->user(),$r->notes);return back()->with('status','Customer group assigned.');} }
